const MyOrdersCashbackView: FC<MyOrdersItemPropsView> = ({
    handleGoBack,
    myOrders,
    emptyImage,
    formatDate,
    isLoading,
    isError,
    modalizeRefFilters,
    handleOpenFilters,
    handleDetailsOrders,
    handleRefresh,
    filterGroups,
    isRefreshing,
    skeletonCount,
    screenWidth
}) => {
    return (
        <BasicScreen
            title="Meus pedidos"
            errorButtonOnPress={() => { }}
            hasScroll
            leftIconOnPress={handleGoBack}
            rightIcon="icon-filter-settings"
            rightIconOnPress={handleOpenFilters}
            hasRightIcon={!!myOrders.length}
            scrollViewProps={{
                refreshControl: (
                    <RefreshControl
                        onRefresh={handleRefresh}
                        refreshing={isRefreshing}
                        tintColor={theme.colors.BRAND_BASE_01}
                    />
                ),
            }}
        >
            {/* Loading, Error, and content rendering */}
        </BasicScreen>
    )
}
export default MyOrdersCashbackView;
